// Package imports:
import 'package:freezed_annotation/freezed_annotation.dart';

part 'jws_transaction_decoded_payload.freezed.dart';
part 'jws_transaction_decoded_payload.g.dart';

/// A decoded payload containing transaction information from Apple's JWT.
///
/// See: https://developer.apple.com/documentation/appstoreserverapi/jwstransactiondecodedpayload
@freezed
abstract class JWSTransactionDecodedPayload
    with _$JWSTransactionDecodedPayload {
  @JsonSerializable(fieldRename: FieldRename.none)
  const factory JWSTransactionDecodedPayload({
    /// The original transaction identifier of a purchase.
    String? originalTransactionId,

    /// The unique identifier for a transaction such as an in-app purchase,
    /// restored in-app purchase, or subscription renewal.
    String? transactionId,

    /// The unique identifier of subscription-purchase events across devices,
    /// including renewals.
    String? webOrderLineItemId,

    /// The bundle identifier of an app.
    String? bundleId,

    /// The unique identifier for the product,
    /// that you create in App Store Connect.
    String? productId,

    /// The identifier of the subscription group
    /// that the subscription belongs to.
    String? subscriptionGroupIdentifier,

    /// The time that the App Store charged the user's account
    /// for an in-app purchase, a restored in-app purchase,
    /// a subscription, or a subscription renewal after a lapse.
    /// UNIX timestamp in milliseconds.
    int? purchaseDate,

    /// The purchase date of the transaction associated
    /// with the original transaction identifier.
    /// UNIX timestamp in milliseconds.
    int? originalPurchaseDate,

    /// The UNIX time, in milliseconds,
    /// an auto-renewable subscription expires or renews.
    int? expiresDate,

    /// The number of consumable products purchased.
    int? quantity,

    /// The type of the in-app purchase.
    /// Values: "Auto-Renewable Subscription", "Non-Consumable",
    /// "Consumable", "Non-Renewing Subscription"
    String? type,

    /// The UUID that an app optionally generates to map
    /// a customer's in-app purchase with its resulting App Store transaction.
    String? appAccountToken,

    /// A string that describes whether the transaction was purchased
    /// by the user, or is available to them through Family Sharing.
    /// Values: "PURCHASED", "FAMILY_SHARED"
    String? inAppOwnershipType,

    /// The UNIX time, in milliseconds,
    /// that the App Store signed the JSON Web Signature data.
    int? signedDate,

    /// The reason that the App Store refunded the transaction
    /// or revoked it from family sharing.
    /// 1: App Store refunded the transaction for an app that the customer purchased by mistake.
    /// 0: App Store refunded the transaction for another reason.
    int? revocationReason,

    /// The UNIX time, in milliseconds,
    /// that Apple Support refunded a transaction.
    int? revocationDate,

    /// The Boolean value that indicates whether
    /// the user upgraded to another subscription.
    bool? isUpgraded,

    /// A value that represents the promotional offer type.
    /// 1: An introductory offer
    /// 2: A promotional offer
    /// 3: An offer with a subscription offer code
    int? offerType,

    /// The identifier that contains the promo code
    /// or the promotional offer identifier.
    String? offerIdentifier,

    /// The server environment, either sandbox or production.
    /// Values: "Sandbox", "Production"
    String? environment,

    /// The three-letter code that represents the country or region
    /// associated with the App Store storefront for the purchase.
    String? storefront,

    /// An Apple-defined value that uniquely identifies
    /// the App Store storefront associated with the purchase.
    String? storefrontId,

    /// The reason for the purchase transaction,
    /// which indicates whether it's a customer's purchase
    /// or a renewal for an auto-renewable subscription
    /// that the system initiates.
    /// Values: "PURCHASE", "RENEWAL"
    String? transactionReason,

    /// The three-letter ISO 4217 currency code
    /// for the price of the product.
    String? currency,

    /// The price, in milliunits, of the in-app purchase
    /// or subscription offer that you configured in App Store Connect.
    int? price,

    /// The payment mode you configure for an introductory offer,
    /// promotional offer, or offer code on an auto-renewable subscription.
    /// Values: "PAY_AS_YOU_GO", "PAY_UP_FRONT", "FREE_TRIAL"
    String? offerDiscountType,

    /// The unique identifier of the app download transaction.
    String? appTransactionId,

    /// The duration of the offer.
    String? offerPeriod,
  }) = _JWSTransactionDecodedPayload;

  factory JWSTransactionDecodedPayload.fromJson(Map<String, dynamic> json) =>
      _$JWSTransactionDecodedPayloadFromJson(json);
}

