// Dart imports:
import 'dart:async';

// Flutter imports:
import 'package:flutter/services.dart';

// Package imports:
import 'package:fimber/fimber.dart';
import 'package:in_app_purchase/in_app_purchase.dart';
import 'package:in_app_purchase_storekit/in_app_purchase_storekit.dart';
import 'package:riverpod_annotation/riverpod_annotation.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/team_list_controller.dart';
import 'package:baseball_detector_flutter/data/models/failure/bad_request_failure.dart';
import 'package:baseball_detector_flutter/data/models/in_app_purchase/current_entitlement.dart';
import 'package:baseball_detector_flutter/providers/profile_storage_provider.dart';
import 'package:baseball_detector_flutter/providers/repository_provider.dart';
import 'package:baseball_detector_flutter/utils/jws_decoder.dart';
import 'package:baseball_detector_flutter/utils/platform.dart';

part 'subscription_controller.g.dart';

const _iap = MethodChannel('jp.knowhere/iap_bridge');

@riverpod
class PurchaseFlowLoading extends _$PurchaseFlowLoading {
  @override
  bool build() => false;

  void update(bool value) {
    state = value;
  }
}

@Riverpod(keepAlive: true)
class SubscriptionController extends _$SubscriptionController {
  static final _logger = FimberLog('SubscriptionController');
  static final Set<String> _processedIds = {};
  StreamSubscription<List<PurchaseDetails>>? _purchaseStreamSubscription;

  @override
  Future<CurrentEntitlement?> build() async {
    // 購入ストリームの購読と現在の権利情報の初期取得を行う
    _startListeningToPurchaseStream();
    updateCurrentEntitlement();
    ref.onDispose(_dispose);
    return null;
  }

  Future<void> _startListeningToPurchaseStream() async {
    _purchaseStreamSubscription = InAppPurchase.instance.purchaseStream.listen(
      (purchases) async {
        for (final purchase in purchases) {
          await handlePurchase(purchase);
        }
      },
      onError: (error) {
        _logger.d('Error in purchase stream', ex: error);
      },
    );
  }

  /// 購入の復元（iOS のみ）。
  /// Android は購入更新ストリーム経由で自動復元されるため、ここでは何もしない。
  Future<void> restorePurchases() async {
    if (!isIos) return;
    try {
      final ios = InAppPurchase.instance
          .getPlatformAddition<InAppPurchaseStoreKitPlatformAddition>();
      await ios.sync();
    } on PlatformException catch (e) {
      // キャンセル以外のエラーは呼び出し元へ伝播
      if (e.details == 'userCancelled') return;
      rethrow;
    }
  }

  void _dispose() {
    _purchaseStreamSubscription?.cancel();
  }

  Future<void> updateCurrentEntitlement() async {
    try {
      final raw = await _iap.invokeMethod<List<dynamic>>('currentEntitlements');

      if (raw == null || raw.isEmpty) {
        _logger.i("Current Entitlement: null");
        state = AsyncValue.data(null);
        return;
      }

      // SubscriptionGroup が 1 つしか存在せず、Family Sharing も有効になっていない場合、
      // 有効な entitlement は最大で 1 つしか返ってこない
      final entitlement = raw.first;
      final map = Map<String, dynamic>.from(
          (entitlement as Map).cast<String, dynamic>());
      final currentEntitlement = CurrentEntitlement.fromJson(map);

      state = AsyncValue.data(currentEntitlement);
      _logger.i("Current Entitlement: $currentEntitlement");
    } catch (e, _) {
      _logger.e('Failed to fetch current entitlements', ex: e);
    }
  }

  Future<bool> purchaseSubscription(ProductDetails productDetails) async {
    try {
      final teamId = ref.read(profileStorageProvider).getTeamId();
      final param = PurchaseParam(
        productDetails: productDetails,
        applicationUserName: teamId,
      );
      // サブスクリプション商品の場合はbuyNonConsumableを使用
      return await InAppPurchase.instance
          .buyNonConsumable(purchaseParam: param);
    } catch (e, stackTrace) {
      if (e is PlatformException && e.code == 'storekit2_purchase_cancelled') {
        rethrow;
      }

      _logger.e('Error initiating purchase', ex: e, stacktrace: stackTrace);
      rethrow;
    }
  }

  Future<void> handlePurchase(PurchaseDetails purchase) async {
    _logger.i(
      "handlePurchase : ${purchase.purchaseID} ${purchase.transactionDate} ${purchase.status}",
    );

    switch (purchase.status) {
      case PurchaseStatus.pending:
        // ここでは特に何もしない
        return;
      case PurchaseStatus.purchased:
      case PurchaseStatus.restored:
        // 購入完了時の処理。
        // in_app_purchase_storekit 0.4.4 の既知の挙動:
        // - 初回購入でも PurchaseStatus が restored になる場合がある
        // - purchase.pendingCompletePurchase が常に false
        // そのため常にサーバー検証を行い、成功時のみ completePurchase する。
        // サーバー側は ASSN v2 経由で冪等に処理される前提。
        try {
          final decodedPayload = JwsDecoder.decodeTransactionPayload(
            purchase.verificationData.serverVerificationData,
          );

          final teamId = ref.read(profileStorageProvider).getTeamId();

          if (decodedPayload?.appAccountToken != teamId) {
            // appAccountToken が一致しない: ユーザーが Team/User を切り替えた可能性。
            // 自動更新分はサーバー側で検証するため、ここでは complete のみ行いストリームを捌く。
            await InAppPurchase.instance.completePurchase(purchase);
            _logger.i(
              "App Account Token does not match. Expected: $teamId, Actual: ${decodedPayload?.appAccountToken}",
            );
            return;
          }

          if (decodedPayload?.transactionReason == 'RENEWAL') {
            // 自動更新分はサーバー側で検証するため、ここでは complete のみ行いストリームを捌く。
            await InAppPurchase.instance.completePurchase(purchase);
            _logger.i("Auto renew subscription: $decodedPayload");
            return;
          }

          final transactionId =
              purchase.purchaseID ?? decodedPayload?.transactionId;
          final webOrderLineItemId = decodedPayload?.webOrderLineItemId;

          if (webOrderLineItemId == null || transactionId == null) {
            // webOrderLineItemId が null の場合は処理をスキップ
            _logger.e(
                "webOrderLineItemId: $webOrderLineItemId transactionId $transactionId is null, cannot verify purchase");
            return;
          }

          if (_processedIds.contains(webOrderLineItemId)) {
            // 同一 webOrderLineItemId が同時に流れてきた場合の重複処理を防止
            // in_app_purchase_storekit のバグで同一 ID でいくつもの purchase が流れてくることがある
            await InAppPurchase.instance.completePurchase(purchase);
            _logger.i(
                "webOrderLineItemId $webOrderLineItemId is already being processed, skipping server validation");
            return;
          } else {
            // 処理済みの webOrderLineItemId を Set に追加
            _processedIds.add(webOrderLineItemId);
          }

          final result = await ref.read(repositoryProvider).verifyTransaction(
                transactionId: transactionId,
                webOrderLineItemId: webOrderLineItemId,
              );

          if (result.hasRight) {
            // サーバー検証成功: complete 実行と entitlement の更新
            await InAppPurchase.instance.completePurchase(purchase);
            ref.read(purchaseFlowLoadingProvider.notifier).update(true);
            await updateCurrentEntitlement();

            _logger.i('Verify Transaction succeeded: $decodedPayload');

            // アップグレード、自動更新ではサーバー側で Webhook を受け取って処理するため refresh するまでの
            // 遅延を入れて反映させる
            await Future.delayed(Duration(seconds: 8));
            await ref
                .read(teamListControllerProvider.notifier)
                .refreshKeepingPrevious();
            await updateCurrentEntitlement();
          } else {
            // 既に処理済みエラー: ストリームから取り除くため complete 実行
            if (result.left is AlreadyProcessedAppleTransactionFailure) {
              await InAppPurchase.instance.completePurchase(purchase);
              await updateCurrentEntitlement();
              _logger.i(
                  "Error message ${result.left.message} returned. So completePurchase to remove this transaction from PurchaseStream. $decodedPayload");
              return;
            }

            // サーバー検証失敗: complete せず、次回起動時に StoreKit が再送する想定。
            _logger.e(
              "Failed to create Apple Payment Session: ${result.left.message}. $decodedPayload",
              ex: result.left,
            );
            // 再試行できるよう Set から除外
            _processedIds.remove(webOrderLineItemId);
          }
        } catch (e, stackTrace) {
          _logger.e(
            'Error handling purchase for ${purchase.purchaseID}',
            ex: e,
            stacktrace: stackTrace,
          );
        } finally {
          ref.read(purchaseFlowLoadingProvider.notifier).update(false);
        }
      case PurchaseStatus.error:
        _logger.e("Purchase error: ${purchase.error}", ex: purchase.error);
        return;
      case PurchaseStatus.canceled:
        return;
    }
  }
}

import Flutter
import StoreKit
import UIKit

@main
@objc class AppDelegate: FlutterAppDelegate {
    override func application(
        _ application: UIApplication,
        didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?
    ) -> Bool {
        let controller: FlutterViewController = window?.rootViewController as! FlutterViewController

        let channel = FlutterMethodChannel(
            name: "baseball_detector_flutter/method",
            binaryMessenger: controller.binaryMessenger
        )
        channel.setMethodCallHandler {
            [weak self] (call: FlutterMethodCall, result: @escaping FlutterResult) in
            if call.method == "setExcludedFromICloudBackup" {
                let args = call.arguments as! [String: Any]
                let path = args["path"] as! String

                do {
                    try self?.setExcludedFromICloudBackup(to: path)
                    result(true)
                } catch {
                    result(
                        FlutterError(
                            code: "FAILED_TO_SET_RESOURCE_VALUE",
                            message: "Failed to exclude path from backup",
                            details: error.localizedDescription
                        ))
                }
            } else if call.method == "beginRefundRequest" {
                guard let args = call.arguments as? [String: Any],
                    let productId = args["productId"] as? String
                else {
                    result(
                        FlutterError(
                            code: "INVALID_ARGUMENTS",
                            message: "productId is required",
                            details: nil))
                    return
                }

                Task { @MainActor in
                    await self?.handleRefundRequest(productId: productId, result: result)
                }
            } else {
                result(FlutterMethodNotImplemented)
            }
        }

        // StoreKit 2 currentEntitlements を返す
        let iapChannel = FlutterMethodChannel(
            name: "jp.knowhere/iap_bridge",
            binaryMessenger: controller.binaryMessenger
        )
        iapChannel.setMethodCallHandler {
            (call: FlutterMethodCall, result: @escaping FlutterResult) in
            switch call.method {
            case "currentEntitlements":
                if #available(iOS 15.0, *) {
                    Task {
                        var rows: [[String: Any]] = []
                        let iso = ISO8601DateFormatter()

                        // AsyncSequence をスナップショット化して返却
                        for await status in Transaction.currentEntitlements {
                            guard case .verified(let t) = status else { continue }

                            // ProductID がサブスクであれば公式の Status を取得
                            var statusStates: [String]? = nil
                            do {
                                let products = try await Product.products(for: [t.productID])
                                if let sub = products.first?.subscription {
                                    let st = try await sub.status // [Product.SubscriptionInfo.Status]
                                    statusStates = st.map { s in
                                        switch s.state {
