                    final linkTextStyle = theme.textTheme.bodySmall?.copyWith(
                      color: theme.colorScheme.onSurfaceVariant,
                      decoration: TextDecoration.underline,
                    );
                    Widget buildLink(
                      String label,
                      VoidCallback onTap, {
                      bool withSeparator = false,
                    }) {
                      return Row(
                        mainAxisSize: MainAxisSize.min,
                        children: [
                          if (withSeparator) ...[
                            Text(
                              '|',
                              style: theme.textTheme.bodySmall?.copyWith(
                                color: theme.colorScheme.onSurfaceVariant,
                              ),
                            ),
                            const Gap(2),
                          ],
                          TextButton(
                            onPressed: onTap,
                            child: Text(
                              label,
                              style: linkTextStyle,
                            ),
                          ),
                        ],
                      );
                    }

                    return Column(
                      children: [
                        Expanded(
                          child: SingleChildScrollView(
                            child: Column(
                              mainAxisSize: MainAxisSize.max,
                              children: [
                                const Gap(12),
                                // プランカードを縦に並べて表示
                                ...plansList.map((plan) {
                                  final isDefaultPlan = currentPlan != null &&
                                      plan.planType == currentPlan;

                                  // PlanType に基づいてバッジタイプを決定
                                  final badgeType = switch (plan.planType) {
                                    PlanType.light => null,
                                    PlanType.standard =>
                                      SubscriptionBadgeType.recommended,
                                    PlanType.premium =>
                                      SubscriptionBadgeType.bestValue,
                                    PlanType.forMultipleTeam => null,
                                  };

                                  return Padding(
                                    padding: const EdgeInsets.only(bottom: 12),
                                    child: SubscriptionPlanCard(
                                      plan: plan,
                                      badgeType: badgeType,
                                      isSelected:
                                          selectedPlan.value?.planType ==
                                              plan.planType,
                                      isCurrentPlan: isDefaultPlan,
                                      cancelScheduledAt: isDefaultPlan
                                          ? cancelScheduledAt
                                          : null,
                                      downgradeScheduledAt: isDefaultPlan
                                          ? downgradeScheduledAt
                                          : null,
                                      downgradePlanName: isDefaultPlan
                                          ? downgradePlanName
                                          : null,
                                      onTap: () {
                                        HapticFeedback.lightImpact();
                                        selectedPlan.value = plan;
                                      },
                                    ),
                                  );
                                }),
                                const Gap(4),
                                Padding(
                                  padding: const EdgeInsets.symmetric(
                                      horizontal: 12),
                                  child: Text(
                                    context.l10n.subscription_page__usage_note,
                                    style: theme.textTheme.bodySmall?.copyWith(
                                      color: theme.colorScheme.onSurfaceVariant,
                                    ),
                                  ),
                                ),
                                TextButton(
                                  onPressed: openSubscriptionSettings,
                                  child: Text(
                                    context.l10n
                                        .subscription_page__cancel_subscription,
                                    style: theme.textTheme.bodySmall?.copyWith(
                                      color: theme.colorScheme.onSurfaceVariant,
                                      decoration: TextDecoration.underline,
                                    ),
                                  ),
                                ),
                                TextButton(
                                  onPressed: () async {
                                    try {
                                      final planManagementUrl =
                                          '${Constants.webURL}/account/plans';
                                      await openURLWithSystemBrowser(
                                        url: planManagementUrl,
                                      );
                                    } catch (e) {
                                      if (context.mounted) {
                                        context.showErrorSnackBar(
                                          context.l10n
                                              .cancel_subscription_page__error_opening_settings,
                                        );
                                      }
                                    }
                                  },
                                  child: Text(
                                    context.l10n.subscription_page__manage_plan,
                                    style: theme.textTheme.bodySmall?.copyWith(
                                      color: theme.colorScheme.onSurfaceVariant,
                                      decoration: TextDecoration.underline,
                                    ),
                                  ),
                                ),
                              ],
                            ),
                          ),
                        ),
                        Column(
                          mainAxisSize: MainAxisSize.min,
                          children: [
                            SizedBox(
                              width: double.infinity,
                              height: 56,
                              child: ElevatedButton(
                                onPressed: selectedPlan.value != null
                                    ? () async {
                                        if (selectedPlan.value == null) {
                                          context.showErrorSnackBar(
                                            context.l10n
                                                .subscription_page__plan_info_unavailable,
                                          );
                                          return;
                                        }

                                        if (!canSubscribe && message != null) {
                                          context.showErrorSnackBar(message);
                                          return;
                                        }

                                        try {
                                          await ref
                                              .read(
                                                  subscriptionControllerProvider
                                                      .notifier)
                                              .purchaseSubscription(
                                                selectedPlan
                                                    .value!.productDetails,
                                              );
                                          if (context.mounted) {
                                            Navigator.of(context).pop();
                                          }
                                        } catch (e) {
                                          if (e is PlatformException &&
                                              e.code ==
                                                  'storekit2_purchase_cancelled') {
                                            return;
                                          }
                                          if (!context.mounted) return;
                                          context.showErrorSnackBar(
                                            context.l10n
                                                .subscription_page__purchase_failed(
                                                    e.toString()),
                                          );
                                        }
                                      }
                                    : null,
                                style: ElevatedButton.styleFrom(
                                  backgroundColor: theme.colorScheme.primary,
                                  foregroundColor: theme.colorScheme.onPrimary,
                                  disabledBackgroundColor:
                                      theme.colorScheme.surfaceDim,
                                  shape: RoundedRectangleBorder(
                                    borderRadius: BorderRadius.circular(12),
                                  ),
                                  elevation: 2,
                                ),
                                child: Text(
                                  context.l10n
                                      .subscription_page__start_plan(planName),
                                  style: const TextStyle(
                                    fontSize: 16,
                                    fontWeight: FontWeight.bold,
                                  ),
                                ),
                              ),
                            ),
                            Wrap(
                              alignment: WrapAlignment.center,
                              crossAxisAlignment: WrapCrossAlignment.center,
                              spacing: 2,
                              runSpacing: 4,
                              children: [
                                buildLink(
                                  context.l10n.settings_page__terms,
                                  openTermsOfUse,
                                ),
                                buildLink(
                                  context.l10n.settings_page__privacy,
                                  openPrivacyPolicy,
                                  withSeparator: true,
                                ),
                                if (isIos)
                                  // 購入の復元（非同期処理は同期ラッパーで起動）
                                  buildLink(
                                    context.l10n.subscription_page__restore,
                                    () {
                                      () async {
                                        try {
                                          await ref
                                              .read(
                                                  subscriptionControllerProvider
                                                      .notifier)
                                              .restorePurchases();
                                        } catch (e) {
                                          if (!context.mounted) return;
                                          context
                                              .showErrorSnackBar(e.toString());
                                        }
                                      }();
                                    },
                                    withSeparator: true,
                                  ),
                              ],
                            ),
                          ],
                        ),
                      ],
                    );
                  }),
                  loading: () => const Center(child: CustomLoadingIndicator()),
                  error: (error, stack) => Center(
                    child: Column(
                      children: [
                        const Icon(
                          Icons.error_outline,
                          size: 48,
                          color: Colors.red,
                        ),
                        const Gap(16),
                        Text(
                          context.l10n.subscription_page__loading_plans_error,
                          style: theme.textTheme.bodyLarge,
                        ),
                        const Gap(8),
                        TextButton(
                          onPressed: () =>
                              ref.refresh(appStoreProductControllerProvider),
                          child: Text(
                              context.l10n.subscription_page__retry_button),
                        ),
                      ],
                    ),
                  ),
                ),
              ),
            ),
          ),
        ),
      ],
    );
  }
}

