import Flutter
import StoreKit
import UIKit

@main
@objc class AppDelegate: FlutterAppDelegate {
    override func application(
        _ application: UIApplication,
        didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?
    ) -> Bool {
        let controller: FlutterViewController = window?.rootViewController as! FlutterViewController

        let channel = FlutterMethodChannel(
            name: "baseball_detector_flutter/method",
            binaryMessenger: controller.binaryMessenger
        )
        channel.setMethodCallHandler {
            [weak self] (call: FlutterMethodCall, result: @escaping FlutterResult) in
            if call.method == "setExcludedFromICloudBackup" {
                let args = call.arguments as! [String: Any]
                let path = args["path"] as! String

                do {
                    try self?.setExcludedFromICloudBackup(to: path)
                    result(true)
                } catch {
                    result(
                        FlutterError(
                            code: "FAILED_TO_SET_RESOURCE_VALUE",
                            message: "Failed to exclude path from backup",
                            details: error.localizedDescription
                        ))
                }
            } else if call.method == "beginRefundRequest" {
                guard let args = call.arguments as? [String: Any],
                    let productId = args["productId"] as? String
                else {
                    result(
                        FlutterError(
                            code: "INVALID_ARGUMENTS",
                            message: "productId is required",
                            details: nil))
                    return
                }

                Task { @MainActor in
                    await self?.handleRefundRequest(productId: productId, result: result)
                }
            } else {
                result(FlutterMethodNotImplemented)
            }
        }

        // StoreKit 2 currentEntitlements を返す
        let iapChannel = FlutterMethodChannel(
            name: "jp.knowhere/iap_bridge",
            binaryMessenger: controller.binaryMessenger
        )
        iapChannel.setMethodCallHandler {
            (call: FlutterMethodCall, result: @escaping FlutterResult) in
            switch call.method {
            case "currentEntitlements":
                if #available(iOS 15.0, *) {
                    Task {
                        var rows: [[String: Any]] = []
                        let iso = ISO8601DateFormatter()

                        // AsyncSequence をスナップショット化して返却
                        for await status in Transaction.currentEntitlements {
                            guard case .verified(let t) = status else { continue }

                            // ProductID がサブスクであれば公式の Status を取得
                            var statusStates: [String]? = nil
                            do {
                                let products = try await Product.products(for: [t.productID])
                                if let sub = products.first?.subscription {
                                    let st = try await sub.status // [Product.SubscriptionInfo.Status]
                                    statusStates = st.map { s in
                                        switch s.state {
                                        case .subscribed: return "subscribed"
                                        case .inGracePeriod: return "inGracePeriod"
                                        case .inBillingRetryPeriod: return "inBillingRetryPeriod"
                                        case .expired: return "expired"
                                        case .revoked: return "revoked"
                                        default: return "unknown"
                                        }
                                    }
                                }
                            } catch {
                                // 取得に失敗した場合は nil のまま（クライアント側でフォールバック）
                            }

                            rows.append([
                                "id": String(t.id),
                                "webOrderLineItemID": t.webOrderLineItemID,
                                "productId": t.productID,
                                "purchaseDate": iso.string(from: t.purchaseDate),
                                "originalId": String(t.originalID),
                                "originalPurchaseDate": iso.string(from: t.originalPurchaseDate),
                                "expirationDate": t.expirationDate.map { iso.string(from: $0) }
                                    as Any,
                                "revocationDate": t.revocationDate.map { iso.string(from: $0) }
                                    as Any,
                                "revocationReason": t.revocationReason?.rawValue as Any,
                                "isUpgraded": t.isUpgraded,
                                // 公式ステータス（存在すれば配列、非サブスク等は nil）
                                "status": statusStates as Any,
                                // Swift の UUID#uuidString は大文字を返すため、小文字に正規化して返却
                                "appAccountToken": t.appAccountToken.map { $0.uuidString.lowercased() } as Any,
                                // ストアフロント情報（3文字の国コード）
                                "storefront": t.storefront as Any,
                            ])
                        }
                        result(rows)
                    }
                } else {
                    result(
                        FlutterError(
                            code: "iOS_VERSION",
                            message: "StoreKit 2 requires iOS 15+",
                            details: nil
                        ))
                }

            // （任意）ユーザー操作で最新化したい時に呼べる sync
            case "sync":
                if #available(iOS 15.0, *) {
                    Task {
                        do {
                            try await AppStore.sync()  // App Store の状態同期
                            result(true)
                        } catch {
                            result(
                                FlutterError(
                                    code: "SYNC_FAILED", message: error.localizedDescription,
                                    details: nil))
                        }
                    }
                } else {
                    result(
                        FlutterError(
                            code: "iOS_VERSION", message: "StoreKit 2 requires iOS 15+",
                            details: nil))
                }

            default:
                result(FlutterMethodNotImplemented)
            }
        }

        GeneratedPluginRegistrant.register(with: self)
        return super.application(application, didFinishLaunchingWithOptions: launchOptions)
    }

    private func setExcludedFromICloudBackup(to path: String) throws {
        let url = NSURL.fileURL(withPath: path) as NSURL
        do {
            try url.setResourceValue(true, forKey: URLResourceKey.isExcludedFromBackupKey)
        } catch {
            print("Error excluding \(url.lastPathComponent ?? "(nil)") from backup: \(error)")
            throw error
        }
    }

    @MainActor
    private func handleRefundRequest(productId: String, result: @escaping FlutterResult) async {
        // iOS 15+ / StoreKit 2 が必要
        if #available(iOS 15.0, *) {
            do {
                // 該当商品の最新トランザクションを取得
                if let verification = try await Transaction.latest(for: productId),
                    case .verified(let transaction) = verification
                {

                    // 現在のウィンドウシーンを取得
                    guard
                        let windowScene = UIApplication.shared.connectedScenes.first
                            as? UIWindowScene
                    else {
                        result(
                            FlutterError(
                                code: "NO_WINDOW_SCENE",
                                message: "Could not find window scene",
                                details: nil))
                        return
                    }

                    // 返金リクエストを開始
                    let refundResult = try await transaction.beginRefundRequest(in: windowScene)

                    // 結果に応じて適切な値を返す
                    switch refundResult {
                    case .success:
                        result("success")
                    case .userCancelled:
                        result("userCancelled")
                    @unknown default:
                        result("error")
                    }

                } else {
                    result(
                        FlutterError(
                            code: "TRANSACTION_NOT_FOUND",
                            message: "No transaction found for product: \(productId)",
                            details: nil))
                }
            } catch {
                result(
                    FlutterError(
                        code: "REFUND_ERROR",
                        message: "Failed to process refund request: \(error.localizedDescription)",
                        details: nil))
            }
        } else {
            result(
                FlutterError(
                    code: "UNSUPPORTED_IOS_VERSION",
                    message: "Refund functionality requires iOS 15 or later",
                    details: nil))
        }
    }
}

message.content:
以下のどちらかの方法で取得できます。Flutter からはそのまま直接は取れないので、iOS ネイティブ（Swift）で取得 → MethodChannel で Dart に渡すのが実運用です。

# 1) StoreKit 2（推奨／iOS 15+）

StoreKit 2 の `Storefront.current`（非同期）で、ユーザーの App Store “storefront”（国・地域）を取得できます。`countryCode` は ISO 3166-1 の3文字コード（例: JPN/USA）です。ストアフロントが変わったときは非同期シーケンスから更新が流れます。([Apple Developer][1])

**Swift（iOS 側）**

```swift
import Flutter
import UIKit
import StoreKit

@main
class AppDelegate: FlutterAppDelegate {
  override func application(
    _ application: UIApplication,
    didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?
  ) -> Bool {

    let controller: FlutterViewController = window?.rootViewController as! FlutterViewController
    let channel = FlutterMethodChannel(name: "app.storefront", binaryMessenger: controller.binaryMessenger)

    channel.setMethodCallHandler { call, result in
      if call.method == "getStorefront" {
        Task { @MainActor in
          if #available(iOS 15.0, *) {
            if let s = await StoreKit.Storefront.current {
              result(["countryCode": s.countryCode, "id": s.id])
              return
            }
          }
          // フォールバック（iOS 13+ の StoreKit 1）
          if let s = SKPaymentQueue.default().storefront {
            result(["countryCode": s.countryCode, "id": s.identifier])
          } else {
            result(nil) // まだ取得できない場合
          }
        }
      } else {
        result(FlutterMethodNotImplemented)
      }
    }

    return super.application(application, didFinishLaunchingWithOptions: launchOptions)
  }
}
```

**Dart（Flutter 側）**

```dart
import 'package:flutter/services.dart';

class Storefront {
  final String countryCode; // 例: "JPN"
  final String id;          // App Store storefront ID
  Storefront({required this.countryCode, required this.id});
}

const _ch = MethodChannel('app.storefront');

Future<Storefront?> getStorefront() async {
  final map = await _ch.invokeMapMethod<String, dynamic>('getStorefront');
  if (map == null) return null;
  return Storefront(countryCode: map['countryCode'], id: map['id']);
}
```

# 2) StoreKit 1 のフォールバック（必要な場合のみ）

`SKPaymentQueue.default().storefront` で同様に取得できます。ただし **iOS 18 以降は StoreKit 1 周辺 API が段階的に非推奨**になっており、今後は StoreKit 2 への移行が前提です。`storefront` は同期 API ですが取得に時間がかかることがあるため、**メインスレッドでは呼ばない**のが推奨です。また、ストアフロント変更時はオブザーバに通知が来ます。([Apple Developer][2])

---

## 注意点・ハマりどころ

* **取得できない/間違っているように見える**
  サンドボックスやデバイス設定によっては、期待と違うコードを返す報告があります。テストでは `.storekit` の「Default Storefront」を使う・サンドボックスユーザーの地域を変える等で検証してください。([Apple Developer][3])
* **値の意味**
  `countryCode` は 3 文字（例: `JPN`, `USA`）。`id`（StoreKit 2）/`identifier`（StoreKit 1）は App Store の storefront 識別子です。購買ロジックでは `countryCode` を使うのが一般的です。([Apple Developer][4])
* **トランザクションとは別**
  価格の通貨は `Product` や `Transaction` 側から取るのが筋で、「ストアフロント＝通貨」ではありません（購入の通貨やロケールは別プロパティ）。([Apple Developer][5])
* **Apple Music 用の storefront**
  Apple Music の “storefront” は `SKCloudServiceController.requestStorefrontCountryCode` で取れますが、**App Store アカウントのストアフロントとは用途が違う**ので、IAP 目的なら StoreKit を使ってください。([Apple Developer][6])

---

必要なら、このコードを最小プラグイン化（`flutter create --template=plugin`）して渡すこともできます。用途（価格表示の出し分け/配信可否の判定など）も教えてもらえれば、最適な層（Storefront vs. `Product.price`/`currency` など）で組み立てます。

[1]: https://developer.apple.com/documentation/storekit/storefront?utm_source=chatgpt.com "Storefront | Apple Developer Documentation"
[2]: https://developer.apple.com/documentation/storekit/skpaymentqueue/storefront?utm_source=chatgpt.com "storefront | Apple Developer Documentation"
[3]: https://developer.apple.com/forums/thread/785659?utm_source=chatgpt.com "Incorrect storefront country code | Apple Developer Forums"
[4]: https://docs.developer.apple.com/documentation/StoreKit/Storefront/countryCode?utm_source=chatgpt.com "countryCode | Apple Developer Documentation"
[5]: https://developer.apple.com/documentation/storekit/transaction/currency?utm_source=chatgpt.com "currency | Apple Developer Documentation"
[6]: https://developer.apple.com/documentation/storekit/skcloudservicecontroller/requeststorefrontcountrycode%28completionhandler%3A%29?utm_source=chatgpt.com "requestStorefrontCountryCode(completionHandler:) | Apple ..."


