import 'package:flutter/services.dart';

/// StoreKit の Storefront 情報
class Storefront {
  const Storefront({
    required this.countryCode,
    required this.id,
  });

  /// 国コード（ISO 3166-1 alpha-3、例: "JPN", "USA"）
  final String countryCode;

  /// App Store storefront ID
  final String id;
}

const _iapChannel = MethodChannel('jp.knowhere/iap_bridge');

/// StoreKit 2 の Storefront 情報を取得
///
/// iOS 15+ では StoreKit 2 の `Storefront.current` から取得
/// iOS 13-14 では StoreKit 1 の `SKPaymentQueue.storefront` から取得
///
/// 取得できない場合は null を返す
Future<Storefront?> getStorefront() async {
  try {
    final map =
        await _iapChannel.invokeMapMethod<String, dynamic>('getStorefront');
    if (map == null) return null;

    final countryCode = map['countryCode'] as String?;
    final id = map['id'] as String?;

    if (countryCode == null || id == null) return null;

    return Storefront(countryCode: countryCode, id: id);
  } catch (e) {
    return null;
  }
}

